#!/usr/bin/env python3
"""Generate complete roster page with FullCalendar + all features."""
path = "/home/lemon/lemons-ai-agent/frontend/app/roster/page.tsx"

lines = []
def L(s): lines.append(s)

L('"use client";')
L('import { useState, useEffect, useCallback } from "react";')
L('import FullCalendar from "@fullcalendar/react";')
L('import dayGridPlugin from "@fullcalendar/daygrid";')
L('import interactionPlugin from "@fullcalendar/interaction";')
L('import { Loader2, Zap, X, Plus, Edit3, Trash2, UserPlus, CalendarPlus, RotateCcw, Settings2, SlidersHorizontal, Info, Save, Lock, Unlock, BarChart3 } from "lucide-react";')
L('import { Button } from "@/components/ui/button";')
L('')
L('export default function Page() {')
L('const [staff,setStaff]=useState([]);')
L('const [units,setUnits]=useState([]);')
L('const [roles,setRoles]=useState([]);')
L('const [assignments,setAssignments]=useState([]);')
L('const [leaveList,setLeaveList]=useState([]);')
L('const [currentMonth,setCurrentMonth]=useState(new Date().toISOString().slice(0,7));')
L('const [solving,setSolving]=useState(false);')
L('const [loading,setLoading]=useState(true);')
L('const [msg,setMsg]=useState("");')
L('const [showSettings,setShowSettings]=useState(false);')
L('const [settingsTab,setSettingsTab]=useState("constraints");')
L('const [showStaffForm,setShowStaffForm]=useState(false);')
L('const [editStaffId,setEditStaffId]=useState(null);')
L('const [staffForm,setStaffForm]=useState({name:"",role:"RW",home_unit:"A",can_work_units:""});')
L('const [showLeaveForm,setShowLeaveForm]=useState(false);')
L('const [editLeaveId,setEditLeaveId]=useState(null);')
L('const [leaveForm,setLeaveForm]=useState({staff_id:0,start_date:"",end_date:"",leave_type:"annual"});')
L('const [showStats,setShowStats]=useState(false);')
L('const [showReplace,setShowReplace]=useState(null);')

# ── Data Loading ──
L('const loadAll=useCallback(async()=>{try{const[rs,rro,ru,rl]=await Promise.all([fetch("/api/schedule?sub=staff").then(r=>r.json()),fetch("/api/schedule?sub=roles").then(r=>r.json()),fetch("/api/schedule?sub=units").then(r=>r.json()),fetch("/api/schedule?sub=leave").then(r=>r.json())]);if(Array.isArray(rs))setStaff(rs);if(Array.isArray(rro))setRoles(rro);if(Array.isArray(ru))setUnits(ru);if(Array.isArray(rl))setLeaveList(rl);}catch(e){console.error(e);}setLoading(false);},[]);')
L('const loadRoster=useCallback(async()=>{var s=currentMonth+"-01";var d=new Date(s);var e=new Date(d.getFullYear(),d.getMonth()+1,0).toISOString().slice(0,10);var r=await fetch("/api/schedule?sub=roster&start="+s+"&end="+e);var data=await r.json();if(Array.isArray(data))setAssignments(data);},[currentMonth]);')
L('useEffect(function(){loadAll();},[loadAll]);useEffect(function(){loadRoster();},[loadRoster]);')

# ── Helpers ──
L('function unitColor(code){var u=units.find(function(x){return x.code===code;});return u?u.color:"#666";}')
L('function unitName(code){var u=units.find(function(x){return x.code===code;});return u?u.name:code;}')
L('function roleColor(code){var r=roles.find(function(x){return x.code===code;});return r?r.color:"#666";}')
L('function initials(n){return n.slice(0,2);}')
L('function isOnLeave(sid,d){return leaveList.some(function(l){return l.staff_id===sid&&d>=l.start_date&&d<=l.end_date;});}')
L('var activeUnits=units.filter(function(u){return u.is_active!==false;});')
L('var activeStaff=staff.filter(function(s){return s.is_active!==false;});')

# ── Workload Stats ──
L('var workload=activeStaff.map(function(s){var a=assignments.filter(function(x){return x.staff_id===s.id;});return{name:s.name,role:s.role,count:a.length};}).sort(function(a,b){return b.count-a.count;});')

# ── Events for FullCalendar ──
L('var eventsByUnit={};')
L('activeUnits.forEach(function(unit){eventsByUnit[unit.code]=[];});')
L('assignments.forEach(function(a){if(eventsByUnit[a.unit]){var c=a.shift_code==="N"?"#818cf8":a.shift_code==="PA"?"#f59e0b":"#22c55e";var isLocked=a.locked;eventsByUnit[a.unit].push({title:(isLocked?"\\ud83d\\udd12 ":"")+a.staff_name+" "+a.shift_code,start:a.shift_date,allDay:true,backgroundColor:c+"CC",borderColor:c,textColor:"#fff",extendedProps:{id:a.id,staff_id:a.staff_id,staff_name:a.staff_name,shift_code:a.shift_code,unit:a.unit,locked:isLocked}});}});')

# ── Actions ──
L('async function handleSolve(){var s=currentMonth+"-01";var d=new Date(s);var e=new Date(d.getFullYear(),d.getMonth()+1,0).toISOString().slice(0,10);setSolving(true);setMsg("");try{var r=await fetch("/api/schedule",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({action:"solve",start_date:s,end_date:e})});var res=await r.json();if(res.error){setMsg(res.error);return;}setMsg("\\u2705 "+res.status+" \\u00b7 "+res.stats.total_shifts+" shifts \\u00b7 "+res.stats.solve_time_ms+"ms");await loadRoster();}catch(ex){setMsg(String(ex));}finally{setSolving(false);}}')
L('async function handleClear(){if(!confirm("\\u6e05\\u7a7a\\u672c\\u6708\\u6240\\u6709\\u975e\\u9396\\u5b9a\\u6392\\u66f4\\uff1f"))return;for(var i=0;i<assignments.length;i++){var a=assignments[i];if(!a.locked&&a.id){await fetch("/api/schedule",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({action:"delete",id:a.id})});}}setMsg("");await loadRoster();}')
L('async function handleAssign(sid,date,unit){await fetch("/api/schedule",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({action:"assign",staff_id:sid,date,shift_code:"1423",unit})});await loadRoster();setShowReplace(null);}')
L('async function handleDeleteAss(a){await fetch("/api/schedule",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({action:"delete",id:a.id})});setShowReplace({date:a.shift_date,unit:a.unit,removing:a.staff_name});await loadRoster();}')
L('async function handleLock(a){await fetch("/api/schedule",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({action:"assign",staff_id:a.staff_id,date:a.shift_date,shift_code:a.shift_code,unit:a.unit,locked:!a.locked})});await loadRoster();}')
L('async function handleStaffSave(){var uu=staffForm.can_work_units?staffForm.can_work_units.split(",").map(function(s){return s.trim();}).filter(Boolean):[staffForm.home_unit];var body={name:staffForm.name,role:staffForm.role,home_unit:staffForm.home_unit,can_work_units:uu};if(editStaffId)await fetch("/api/schedule",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({action:"staff_update",id:editStaffId,...body})});else await fetch("/api/schedule",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({action:"staff_add",...body})});setShowStaffForm(false);setEditStaffId(null);setStaffForm({name:"",role:"RW",home_unit:"A",can_work_units:""});await loadAll();}')
L('async function handleStaffDelete(id,name){if(!confirm("\\u522a\\u9664 "+name+"\\uff1f"))return;await fetch("/api/schedule",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({action:"staff_delete",id})});await loadAll();await loadRoster();}')
L('async function handleLeaveSave(){await fetch("/api/schedule",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({action:"leave_save",id:editLeaveId,...leaveForm})});setShowLeaveForm(false);setEditLeaveId(null);setLeaveForm({staff_id:0,start_date:"",end_date:"",leave_type:"annual"});await loadAll();}')
L('async function handleLeaveDelete(id){if(!confirm("\\u522a\\u9664\\uff1f"))return;await fetch("/api/schedule",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({action:"leave_delete",id})});await loadAll();}')

# ── Replace Suggestions ──
L('function getSuggestions(date,unit,excludeSid){var busy=new Set(assignments.filter(function(a){return a.shift_date===date;}).map(function(a){return a.staff_id;}));var onL=new Set(leaveList.filter(function(l){return date>=l.start_date&&date<=l.end_date;}).map(function(l){return l.staff_id;}));busy.add(excludeSid);return activeStaff.filter(function(s){if(busy.has(s.id)||onL.has(s.id))return false;return s.home_unit===unit||(s.can_work_units||[]).includes(unit);}).slice(0,5);}')

L('if(loading)return <div className="flex items-center justify-center min-h-screen"><Loader2 size={32} className="animate-spin text-indigo-400"/></div>;')

# ── Main Render ──
L('var monthLabel=new Date(currentMonth+"-01").toLocaleDateString("zh-TW",{year:"numeric",month:"long"});')

L('return <div className="p-4 max-w-full">')
L('<style>{`.fc{background:transparent!important;color:#a1a1aa!important}.fc-toolbar-title{font-size:0}.fc-header-toolbar{display:none}.fc-col-header-cell{background:#27272a;border-color:#3f3f46;padding:3px 0;font-size:10px}.fc-daygrid-day{background:#18181b;border-color:#27272a}.fc-day-today{background:#1e1b4b!important}.fc-daygrid-day-number{color:#71717a;font-size:10px;padding:2px 4px}.fc-daygrid-event{border-radius:4px;margin:1px 2px;padding:1px 3px;font-size:9px;border:none;cursor:pointer}.fc-daygrid-event:hover{filter:brightness(1.2)}.fc-daygrid-day-frame{min-height:45px}.fc-scrollgrid{border-color:#27272a!important}.fc-scrollgrid-section-header{border:none!important}`}</style>')

# Header
L('<div className="flex items-center justify-between flex-wrap gap-3 mb-4">')
L('<div><h1 className="text-xl font-bold text-zinc-100 flex items-center gap-2">\\ud83d\\udcc5 智能排更</h1><p className="text-xs text-zinc-500 mt-0.5">{activeStaff.length} staff \\u00b7 {activeUnits.length} units \\u00b7 {assignments.length} shifts</p></div>')
L('<div className="flex items-center gap-2">')
L('<Button variant="secondary" size="sm" onClick={handleClear}><RotateCcw size={13} className="mr-1"/>清空</Button>')
L('<Button variant="secondary" size="sm" onClick={function(){setShowSettings(true);setSettingsTab("constraints");}}><Settings2 size={13} className="mr-1"/>設定</Button>')
L('<Button variant="primary" size="sm" onClick={handleSolve} disabled={solving}>{solving?<Loader2 size={14} className="mr-1 animate-spin"/>:<Zap size={14} className="mr-1"/}{solving?"\\u8a08\\u7b97\\u4e2d":"\\u81ea\\u52d5\\u6392\\u66f4"}</Button>')
L('</div></div>')
L('{msg?<div className="rounded-xl p-3 text-sm bg-emerald-500/10 border border-emerald-500/20 text-emerald-400 mb-4">{msg}</div>:null}')

# Main layout
L('<div className="flex gap-4">')

# Left Panel
L('<div className="w-48 shrink-0 space-y-3">')

# Staff panel
L('<div className="bg-zinc-900/60 border border-zinc-800 rounded-xl"><div className="flex items-center justify-between px-3 pt-3 pb-2"><p className="text-[10px] font-semibold text-zinc-500 uppercase">\\u8077\\u54e1 ({activeStaff.length})</p><button onClick={function(){setEditStaffId(null);setStaffForm({name:"",role:roles[0]?.code||"RW",home_unit:activeUnits[0]?.code||"A",can_work_units:""});setShowStaffForm(true);}} className="text-indigo-400 hover:text-indigo-300"><UserPlus size={13}/></button></div><div className="px-2 pb-2 space-y-0.5 max-h-[250px] overflow-y-auto">')
L('{activeStaff.map(function(s){return <div key={s.id} className="flex items-center gap-1.5 p-1.5 rounded-lg hover:bg-zinc-800/50 text-[11px] group"><div className="w-5 h-5 rounded-full flex items-center justify-center text-[8px] font-bold text-white shrink-0" style={{backgroundColor:unitColor(s.home_unit)}}>{initials(s.name)}</div><span className="text-zinc-300 truncate flex-1">{s.name}</span><div className="hidden group-hover:flex gap-0.5"><button onClick={function(){setEditStaffId(s.id);setStaffForm({name:s.name,role:s.role,home_unit:s.home_unit,can_work_units:(s.can_work_units||[]).join(", ")});setShowStaffForm(true);}} className="p-0.5 hover:bg-zinc-700 rounded"><Edit3 size={9} className="text-zinc-400"/></button><button onClick={function(){handleStaffDelete(s.id,s.name);}} className="p-0.5 hover:bg-red-500/20 rounded"><Trash2 size={9} className="text-red-400"/></button></div></div>;})}')
L('</div></div>')

# Leave panel
L('<div className="bg-zinc-900/60 border border-zinc-800 rounded-xl"><div className="flex items-center justify-between px-3 pt-3 pb-2"><p className="text-[10px] font-semibold text-zinc-500 uppercase">\\u8acb\\u5047</p><button onClick={function(){setEditLeaveId(null);setLeaveForm({staff_id:activeStaff[0]?.id||0,start_date:currentMonth+"-01",end_date:currentMonth+"-01",leave_type:"annual"});setShowLeaveForm(true);}} className="text-amber-400 hover:text-amber-300"><CalendarPlus size={13}/></button></div><div className="px-2 pb-2 space-y-0.5 max-h-[150px] overflow-y-auto">')
L('{leaveList.filter(function(l){return l.end_date>=currentMonth+"-01";}).slice(0,5).map(function(l){return <div key={l.id} className="text-[10px] text-zinc-500 p-1.5 border-b border-zinc-800/50 flex items-center gap-1.5 group"><span className="w-1 h-1 rounded-full bg-amber-500 shrink-0"/><span className="text-zinc-300 truncate flex-1">{l.staff_name}</span><span className="text-zinc-600">{l.start_date}~{l.end_date}</span><button onClick={function(){handleLeaveDelete(l.id);}} className="hidden group-hover:block p-0.5 hover:bg-red-500/20 rounded"><Trash2 size={8} className="text-red-400"/></button></div>;})}')
L('{leaveList.length===0?<p className="text-[10px] text-zinc-600 p-1.5">\\u7121\\u8acb\\u5047\\u8a18\\u9304</p>:null}')
L('</div></div>')

# Stats panel
L('<div className="bg-zinc-900/60 border border-zinc-800 rounded-xl"><div className="flex items-center justify-between px-3 pt-3 pb-2 cursor-pointer" onClick={function(){setShowStats(!showStats);}}><p className="text-[10px] font-semibold text-zinc-500 uppercase flex items-center gap-1"><BarChart3 size={11}/>\\u5de5\\u6642</p><span className="text-[10px] text-zinc-600">{showStats?"\\u25b2":"\\u25bc"}</span></div>')
L('{showStats?<div className="px-2 pb-2 space-y-1 max-h-[200px] overflow-y-auto">{workload.slice(0,8).map(function(w){return <div key={w.name} className="flex items-center gap-1.5 text-[10px] py-0.5"><span className="w-12 truncate text-zinc-300">{w.name}</span><div className="flex-1 h-1 bg-zinc-800 rounded-full overflow-hidden"><div className="h-full rounded-full" style={{width:Math.min(100,w.count/31*100)+"%",backgroundColor:roleColor(w.role)}}/></div><span className="w-6 text-right text-zinc-500">{w.count}</span></div>;})}</div>:null}')
L('</div></div>')

# Right: Calendar Area
L('<div className="flex-1 space-y-2">')
L('{activeUnits.map(function(unit){return <div key={unit.code} className="bg-zinc-900/60 border border-zinc-800 rounded-xl overflow-hidden"><div className="flex items-center gap-2 px-4 py-2 border-b border-zinc-800 bg-zinc-800/30"><div className="w-2.5 h-2.5 rounded-full" style={{backgroundColor:unit.color}}/><span className="text-xs font-semibold text-zinc-300">{unit.name}</span><span className="text-[10px] text-zinc-600 ml-auto">{(eventsByUnit[unit.code]||[]).length} shifts</span></div><div className="p-2">')
L('<FullCalendar plugins={[dayGridPlugin,interactionPlugin]} initialView="dayGridMonth" initialDate={currentMonth+"-01"} events={eventsByUnit[unit.code]||[]} height="auto" headerToolbar={{left:"",center:"",right:""}} datesSet={function(info){setCurrentMonth(info.start.toISOString().slice(0,7));}}')
L('eventClick={function(info){var ep=info.event.extendedProps;if(ep&&ep.id){var a={id:ep.id,staff_id:ep.staff_id,staff_name:ep.staff_name,shift_code:ep.shift_code,unit:ep.unit,locked:ep.locked,shift_date:info.event.startStr};handleDeleteAss(a);}}}')
L('dateClick={function(info){var d=info.dateStr;var s=activeStaff[0];if(s)handleAssign(s.id,d,unit.code);}}')
L('/>')
L('</div></div>;})}')
L('</div>')

L('</div>')  # close flex gap-4

# ── Staff Form Modal ──
L('{showStaffForm?<div className="fixed inset-0 bg-black/60 flex items-center justify-center z-50" onClick={function(){setShowStaffForm(false);}}><div className="bg-zinc-900 border border-zinc-700 rounded-2xl p-5 w-[380px]" onClick={function(e){e.stopPropagation();}}><div className="flex items-center justify-between mb-4"><p className="text-sm font-semibold text-zinc-100">{editStaffId?"\\u7de8\\u8f2f\\u8077\\u54e1":"\\u65b0\\u589e\\u8077\\u54e1"}</p><button onClick={function(){setShowStaffForm(false);}}><X size={16} className="text-zinc-500"/></button></div><div className="space-y-3"><div><label className="text-[10px] text-zinc-500">\\u59d3\\u540d</label><input value={staffForm.name} onChange={function(e){setStaffForm({...staffForm,name:e.target.value});}} className="w-full bg-zinc-800 border border-zinc-700 rounded-xl px-3 py-2.5 text-sm mt-1 text-zinc-100" placeholder="\\u9673\\u4e3b\\u4efb"/></div><div className="flex gap-3"><div className="flex-1"><label className="text-[10px] text-zinc-500">\\u89d2\\u8272</label><select value={staffForm.role} onChange={function(e){setStaffForm({...staffForm,role:e.target.value});}} className="w-full bg-zinc-800 border border-zinc-700 rounded-xl px-3 py-2.5 text-sm mt-1 text-zinc-100">{roles.map(function(r){return <option key={r.code} value={r.code}>{r.name}</option>;})}</select></div><div className="flex-1"><label className="text-[10px] text-zinc-500">\\u5bb6\\u793e</label><select value={staffForm.home_unit} onChange={function(e){setStaffForm({...staffForm,home_unit:e.target.value});}} className="w-full bg-zinc-800 border border-zinc-700 rounded-xl px-3 py-2.5 text-sm mt-1 text-zinc-100">{activeUnits.map(function(u){return <option key={u.code} value={u.code}>{u.name}</option>;})}</select></div></div><div><label className="text-[10px] text-zinc-500">\\u53ef\\u8de8\\u793e (\\u9017\\u865f\\u5206\\u9694)</label><input value={staffForm.can_work_units} onChange={function(e){setStaffForm({...staffForm,can_work_units:e.target.value});}} className="w-full bg-zinc-800 border border-zinc-700 rounded-xl px-3 py-2.5 text-sm mt-1 text-zinc-100" placeholder={staffForm.home_unit}/></div></div><div className="flex gap-2 mt-5"><Button variant="secondary" size="sm" className="flex-1" onClick={function(){setShowStaffForm(false);}}>\\u53d6\\u6d88</Button><Button variant="primary" size="sm" className="flex-1" onClick={handleStaffSave} disabled={!staffForm.name.trim()}>{editStaffId?"\\u5132\\u5b58":"\\u65b0\\u589e"}</Button></div></div></div>:null}')

# ── Leave Form Modal ──
L('{showLeaveForm?<div className="fixed inset-0 bg-black/60 flex items-center justify-center z-50" onClick={function(){setShowLeaveForm(false);}}><div className="bg-zinc-900 border border-zinc-700 rounded-2xl p-5 w-[380px]" onClick={function(e){e.stopPropagation();}}><div className="flex items-center justify-between mb-4"><p className="text-sm font-semibold text-zinc-100">{editLeaveId?"\\u7de8\\u8f2f\\u8acb\\u5047":"\\u65b0\\u589e\\u8acb\\u5047"}</p><button onClick={function(){setShowLeaveForm(false);}}><X size={16} className="text-zinc-500"/></button></div><div className="space-y-3"><div><label className="text-[10px] text-zinc-500">\\u8077\\u54e1</label><select value={leaveForm.staff_id} onChange={function(e){setLeaveForm({...leaveForm,staff_id:Number(e.target.value)});}} className="w-full bg-zinc-800 border border-zinc-700 rounded-xl px-3 py-2.5 text-sm mt-1 text-zinc-100">{activeStaff.map(function(s){return <option key={s.id} value={s.id}>{s.name}</option>;})}</select></div><div className="flex gap-3"><div className="flex-1"><label className="text-[10px] text-zinc-500">\\u958b\\u59cb</label><input type="date" value={leaveForm.start_date} onChange={function(e){setLeaveForm({...leaveForm,start_date:e.target.value});}} className="w-full bg-zinc-800 border border-zinc-700 rounded-xl px-3 py-2.5 text-sm mt-1 text-zinc-100"/></div><div className="flex-1"><label className="text-[10px] text-zinc-500">\\u7d50\\u675f</label><input type="date" value={leaveForm.end_date} onChange={function(e){setLeaveForm({...leaveForm,end_date:e.target.value});}} className="w-full bg-zinc-800 border border-zinc-700 rounded-xl px-3 py-2.5 text-sm mt-1 text-zinc-100"/></div></div><div><label className="text-[10px] text-zinc-500">\\u985e\\u578b</label><select value={leaveForm.leave_type} onChange={function(e){setLeaveForm({...leaveForm,leave_type:e.target.value});}} className="w-full bg-zinc-800 border border-zinc-700 rounded-xl px-3 py-2.5 text-sm mt-1 text-zinc-100"><option value="annual">\\u5e74\\u5047</option><option value="sick">\\u75c5\\u5047</option><option value="time_off">\\u88dc\\u5047</option><option value="training">\\u57f9\\u8a13</option><option value="other">\\u5176\\u4ed6</option></select></div></div><div className="flex gap-2 mt-5"><Button variant="secondary" size="sm" className="flex-1" onClick={function(){setShowLeaveForm(false);}}>\\u53d6\\u6d88</Button><Button variant="primary" size="sm" className="flex-1" onClick={handleLeaveSave} disabled={!leaveForm.staff_id||!leaveForm.start_date}>{editLeaveId?"\\u5132\\u5b58":"\\u65b0\\u589e"}</Button></div></div></div>:null}')

# ── Replace Suggestion Modal ──
L('{showReplace?<div className="fixed inset-0 bg-black/60 flex items-center justify-center z-50" onClick={function(){setShowReplace(null);}}><div className="bg-zinc-900 border border-zinc-700 rounded-2xl p-5 w-[420px]" onClick={function(e){e.stopPropagation();}}><div className="flex items-center justify-between mb-4"><p className="text-sm font-semibold text-zinc-100">\\u66ff\\u4ee3\\u5efa\\u8b70</p><button onClick={function(){setShowReplace(null);}}><X size={16} className="text-zinc-500"/></button></div><p className="text-xs text-zinc-500 mb-3">\\u5df2\\u79fb\\u9664 {showReplace.removing}\\uff0c\\u63a8\\u85a6\\u66ff\\u4ee3\\uff1a</p><div className="space-y-2 max-h-[250px] overflow-y-auto">{getSuggestions(showReplace.date,showReplace.unit,(activeStaff.find(function(s){return s.name===showReplace.removing;})||{}).id||0).map(function(s){return <button key={s.id} onClick={function(){handleAssign(s.id,showReplace.date,showReplace.unit);}} className="w-full text-left p-3 rounded-xl bg-zinc-800/50 hover:bg-zinc-700/50 flex items-center gap-3 group"><div className="w-7 h-7 rounded-full flex items-center justify-center text-[10px] font-bold text-white" style={{backgroundColor:unitColor(s.home_unit)}}>{initials(s.name)}</div><div><p className="text-sm text-zinc-200">{s.name} <span className="text-[10px] text-zinc-500">{s.role}</span></p></div><span className="text-[10px] text-indigo-400 opacity-0 group-hover:opacity-100 ml-auto">\\u9078\\u64c7</span></button>;})}</div></div></div>:null}')

# ── Settings Modal ──
