# ── Constraints Tab ──
L('function ConstraintsTab(props){const[localConfig,setLocalConfig]=useState(null);const[saving,setSaving]=useState(false);const[saved,setSaved]=useState(false);useEffect(function(){fetch("/api/schedule?sub=config").then(function(r){return r.json();}).then(function(d){if(d&&d.config_json)setLocalConfig(d.config_json);});},[]);if(!localConfig)return <div className="text-center py-8"><Loader2 size={24} className="animate-spin text-indigo-400 mx-auto"/></div>;function updateHard(k,f,v){var hc={...localConfig.hard_constraints};hc[k]={...(hc[k]||{})};hc[k][f]=v;setLocalConfig({...localConfig,hard_constraints:hc});}function updateSoft(k,f,v){var sc={...localConfig.soft_constraints};sc[k]={...(sc[k]||{})};sc[k][f]=v;setLocalConfig({...localConfig,soft_constraints:sc});}async function save(){setSaving(true);await fetch("/api/schedule",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({action:"config_save",config_json:localConfig})});setSaving(false);setSaved(true);if(props.onReload)props.onReload();setTimeout(function(){setSaved(false);},2000);}var hc=localConfig.hard_constraints||{};var sc=localConfig.soft_constraints||{};return <div><p className="text-[11px] font-semibold text-zinc-400 mb-2 uppercase tracking-wide">HARD CONSTRAINTS</p><div className="space-y-3 mb-4"><HardRow label="\\u591c\\u66f4\\u5f8c\\u4f11\\u606f" desc="\\u505a\\u591c\\u66f4\\u5f8c\\u6700\\u5c11\\u4f11\\u606f\\u6642\\u6578" unit="\\u5c0f\\u6642" min={0} max={72} step={1} enabled={hc.night_rest_24h?hc.night_rest_24h.enabled!==false:false} value={hc.night_rest_24h?hc.night_rest_24h.hours||24:24} onToggle={function(){updateHard("night_rest_24h","enabled",!((hc.night_rest_24h||{}).enabled!==false));}} onChange={function(v){updateHard("night_rest_24h","hours",v);}}/><HardRow label="\\u9023\\u7e8c\\u5de5\\u4f5c\\u4e0a\\u9650" desc="\\u6bcf\\u4eba\\u6700\\u591a\\u9023\\u7e8c\\u5de5\\u4f5c\\u5929\\u6578" unit="\\u65e5" min={0} max={14} step={1} enabled={hc.max_consecutive_days?hc.max_consecutive_days.enabled!==false:false} value={hc.max_consecutive_days?hc.max_consecutive_days.value||6:6} onToggle={function(){updateHard("max_consecutive_days","enabled",!((hc.max_consecutive_days||{}).enabled!==false));}} onChange={function(v){updateHard("max_consecutive_days","value",v);}}/></div><p className="text-[11px] font-semibold text-zinc-400 mb-2 uppercase tracking-wide">SOFT CONSTRAINTS</p><div className="space-y-3 mb-4">{[{k:"avoid_consecutive_nights",l:"\\u907f\\u514d\\u9023\\u7e8c\\u591c\\u66f4"},{k:"fair_weekend_distribution",l:"\\u516c\\u5e73\\u5206\\u914d\\u9031\\u672b"},{k:"as_avoid_night",l:"\\u4e3b\\u7ba1\\u907f\\u514d\\u591c\\u66f4"},{k:"minimize_cross_unit",l:"\\u6e1b\\u5c11\\u8de8\\u793e\\u8abf\\u52d5"},{k:"same_unit_continuity",l:"\\u540c\\u793e\\u9023\\u7e8c\\u5de5\\u4f5c"},{k:"abc_group_constraint",l:"ABC\\u7d44\\u7d04\\u675f"}].map(function(item){var cfg=sc[item.k]||{};return <SoftRow key={item.k} label={item.l} weight={cfg.weight||0} enabled={cfg.enabled!==false} onToggle={function(){updateSoft(item.k,"enabled",!((sc[item.k]||{}).enabled!==false));}} onChange={function(v){updateSoft(item.k,"weight",v);}}/>;})}</div><div className="flex gap-2"><Button variant="secondary" size="sm" className="flex-1" onClick={props.onClose||function(){}}>\\u95dc\\u9589</Button><Button variant="primary" size="sm" className="flex-1" onClick={save} disabled={saving}>{saved?"\\u5df2\\u5132\\u5b58":"\\u5132\\u5b58\\u8a2d\\u5b9a"}</Button></div></div>;}')

# ── Units Tab ──
L('function UnitsTab(props){var units=props.units||[];var onReload=props.onReload;var[n,setN]=useState("");var[c,setC]=useState("");async function save(id,name,code,color){await fetch("/api/schedule",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({action:"unit_save",id:id||null,name:name,code:code,color:color||"#22c55e"})});if(onReload)onReload();}async function del(id){if(!confirm("\\u522a\\u9664\\uff1f"))return;await fetch("/api/schedule",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({action:"unit_delete",id})});if(onReload)onReload();}return <div className="space-y-2">{units.map(function(u){return <div key={u.id} className="flex items-center gap-3 p-2.5 rounded-xl bg-zinc-800/30 group"><div className="w-3 h-3 rounded-full shrink-0" style={{backgroundColor:u.color}}/><div className="flex-1"><p className="text-xs text-zinc-200">{u.name}</p><p className="text-[10px] text-zinc-600">{u.code}</p></div><div className="hidden group-hover:flex gap-1"><button onClick={function(){var nn=prompt("\\u540d\\u7a31",u.name);if(nn)save(u.id,nn,u.code,u.color);}} className="p-1 hover:bg-zinc-700 rounded"><Edit3 size={10} className="text-zinc-400"/></button><button onClick={function(){del(u.id);}} className="p-1 hover:bg-red-500/20 rounded"><Trash2 size={10} className="text-red-400"/></button></div></div>;})}<div className="flex gap-2 pt-2 border-t border-zinc-800"><input value={n} onChange={function(e){setN(e.target.value);}} placeholder="\\u540d\\u7a31" className="flex-1 bg-zinc-800 border-zinc-700 rounded-lg px-2.5 py-1.5 text-xs text-zinc-200"/><input value={c} onChange={function(e){setC(e.target.value);}} placeholder="\\u4ee3\\u78bc" className="w-16 bg-zinc-800 border-zinc-700 rounded-lg px-2.5 py-1.5 text-xs text-zinc-200"/><Button variant="primary" size="sm" className="text-[10px]" onClick={function(){if(n&&c){save(null,n,c,"#22c55e");setN("");setC("");}}} disabled={!n||!c}><Plus size={12}/></Button></div></div>;}')

# ── Roles Tab ──
L('function RolesTab(props){var roles=props.roles||[];var onReload=props.onReload;var[n,setN]=useState("");var[c,setC]=useState("");var[cl,setCl]=useState("#818cf8");var colors=["#818cf8","#22c55e","#f59e0b","#ef4444","#06b6d4","#ec4899"];async function save(id,name,code,color){await fetch("/api/schedule",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({action:"role_save",id:id||null,name:name,code:code,color:color})});if(onReload)onReload();}async function del(id){if(!confirm("\\u522a\\u9664\\uff1f"))return;await fetch("/api/schedule",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({action:"role_delete",id})});if(onReload)onReload();}return <div className="space-y-2">{roles.map(function(r){return <div key={r.id} className="flex items-center gap-3 p-2.5 rounded-xl bg-zinc-800/30 group"><div className="w-3 h-3 rounded-full shrink-0" style={{backgroundColor:r.color}}/><div className="flex-1"><p className="text-xs text-zinc-200">{r.name}</p><p className="text-[10px] text-zinc-600">{r.code}</p></div><div className="hidden group-hover:flex gap-1"><button onClick={function(){var nn=prompt("\\u540d\\u7a31",r.name);if(nn)save(r.id,nn,r.code,r.color);}} className="p-1 hover:bg-zinc-700 rounded"><Edit3 size={10} className="text-zinc-400"/></button><button onClick={function(){del(r.id);}} className="p-1 hover:bg-red-500/20 rounded"><Trash2 size={10} className="text-red-400"/></button></div></div>;})}<div className="flex gap-2 pt-2 border-t border-zinc-800"><input value={n} onChange={function(e){setN(e.target.value);}} placeholder="\\u540d\\u7a31" className="flex-1 bg-zinc-800 border-zinc-700 rounded-lg px-2.5 py-1.5 text-xs text-zinc-200"/><input value={c} onChange={function(e){setC(e.target.value);}} placeholder="\\u4ee3\\u78bc" className="w-16 bg-zinc-800 border-zinc-700 rounded-lg px-2.5 py-1.5 text-xs text-zinc-200"/><div className="flex gap-1 items-center">{colors.map(function(co){return <button key={co} onClick={function(){setCl(co);}} className={"w-3.5 h-3.5 rounded-full border-2 "+(cl===co?"border-white":"border-transparent")} style={{backgroundColor:co}}/>;})}</div><Button variant="primary" size="sm" className="text-[10px]" onClick={function(){if(n&&c){save(null,n,c,cl);setN("");setC("");}}} disabled={!n||!c}><Plus size={12}/></Button></div></div>;}')

# ── HardRow ──
L('function HardRow(p){return <div className="p-3 rounded-xl bg-zinc-800/30"><div className="flex items-center justify-between mb-2"><div><p className="text-xs font-medium text-zinc-200">{p.label}</p><p className="text-[10px] text-zinc-500 mt-0.5">{p.desc}</p></div><div className={"w-10 h-5 rounded-full transition-colors cursor-pointer shrink-0 "+(p.enabled?"bg-indigo-500":"bg-zinc-600")} onClick={p.onToggle}><div className={"w-4 h-4 rounded-full bg-white mt-0.5 transition-transform "+(p.enabled?"translate-x-5":"translate-x-0.5")}/></div></div>{p.enabled?<div className="flex items-center gap-2"><input type="number" min={p.min} max={p.max} step={p.step} value={p.value} onChange={function(e){p.onChange(parseInt(e.target.value)||0);}} className="w-16 bg-zinc-700 border border-zinc-600 rounded-lg px-2 py-1 text-xs text-zinc-200 text-center"/><span className="text-[10px] text-zinc-500">{p.unit}</span></div>:null}</div>;}')

# ── SoftRow ──
L('function SoftRow(p){return <div className="p-3 rounded-xl bg-zinc-800/30"><div className="flex items-center justify-between mb-2"><p className="text-xs font-medium text-zinc-200">{p.label}</p><div className={"w-10 h-5 rounded-full transition-colors cursor-pointer shrink-0 "+(p.enabled?"bg-indigo-500":"bg-zinc-600")} onClick={p.onToggle}><div className={"w-4 h-4 rounded-full bg-white mt-0.5 transition-transform "+(p.enabled?"translate-x-5":"translate-x-0.5")}/></div></div>{p.enabled?<div className="flex items-center gap-3"><span className="text-[10px] text-zinc-500 w-8">\\u6b0a\\u91cd</span><input type="range" min={0} max={500} step={10} value={p.weight} onChange={function(e){p.onChange(parseInt(e.target.value));}} className="flex-1 h-1 accent-indigo-500"/><span className="text-xs text-indigo-400 font-mono w-8 text-right">{p.weight}</span></div>:null}</div>;}')

